// ── STEP 1: READ REAL DATA FROM GOOGLE SHEETS ──────────────
// No hardcode. No fallback mock data.
// If sheet is empty or no Pending rows → error with clear message.

const rows = $input.all();

if (rows.length === 0) {
  throw new Error('Google Sheets returned 0 rows. Check sheet ID and tab name.');
}

// Case-insensitive Pending filter
const pending = rows.filter(r =>
  r.json.Order_ID &&
  typeof r.json.Status === 'string' &&
  r.json.Status.trim().toLowerCase() === 'pending'
);

if (pending.length === 0) {
  const found = rows.map(r => `${r.json.Order_ID}:${r.json.Status}`).join(', ');
  throw new Error(`No Pending shipments found. Rows in sheet: [${found}]. Set Status to 'Pending'.`);
}

const shipments = pending.map(r => ({
  id:        String(r.json.Order_ID).trim(),
  customer:  String(r.json.Customer  || 'Unknown').trim(),
  dest:      String(r.json.Delivery_Address || '').trim(),
  item:      String(r.json.Item      || 'Unknown').trim(),
  weight_kg: parseFloat(r.json.Weight_kg) || 0,
  priority:  String(r.json.Priority  || 'Medium').trim(),
  carrier:   String(r.json.Assigned_Carrier || 'Unknown').trim()
}));

// Validate — every shipment must have id, dest, weight
shipments.forEach(s => {
  if (!s.id)   throw new Error(`Shipment missing Order_ID`);
  if (!s.dest) throw new Error(`Shipment ${s.id} missing Delivery_Address`);
  if (s.weight_kg <= 0) console.warn(`[WARN] Shipment ${s.id} has weight_kg=${s.weight_kg}`);
});

// Fleet from config (move to sheet if needed)
const fleet = [
  { id:'T01', capacity_kg:500, hours_used:3.5, driver:'Driver A' },
  { id:'T02', capacity_kg:400, hours_used:2.0, driver:'Driver B' },
  { id:'T03', capacity_kg:600, hours_used:1.5, driver:'Driver C' }
];

// Traffic delay factors — keyword matched against destination
const trafficFactors = {
  'San Francisco':1.30, 'Los Angeles':1.40, 'New York':1.35,
  'Chicago':1.20,       'Seattle':1.15,     'Oakland':1.15,
  'San Jose':1.10,      'Berkeley':1.05,    'Boston':1.25,
  'Miami':1.20,         'Dallas':1.10,      'Houston':1.15
};

const runId = 'RUN-' + Date.now();
console.log(`[Init] ${runId} | ${shipments.length} shipments | IDs: ${shipments.map(s=>s.id).join(', ')}`);

return [{ json: {
  run_id: runId,
  timestamp: new Date().toISOString(),
  total_shipments: shipments.length,
  shipments,
  fleet,
  trafficFactors,
  hos_limit: 11
}}];

// ── STEP 2: COMPUTE EVERYTHING IN CODE ─────────────────────
// No LLM for math. Pure deterministic computation.
// Groq is used only for natural language summary at the end.

const d = $input.first().json;
const { shipments, fleet, trafficFactors, hos_limit, run_id } = d;

// ── 1. Sort by priority ──────────────────────────────────────
const PRI = { High:0, Medium:1, Low:2 };
const sorted = [...shipments].sort((a,b) =>
  (PRI[a.priority] ?? 1) - (PRI[b.priority] ?? 1)
);

// ── 2. Get traffic factor for a destination ──────────────────
function getFactor(dest) {
  for (const [key, val] of Object.entries(trafficFactors)) {
    if (dest.toLowerCase().includes(key.toLowerCase())) return val;
  }
  return 1.0; // no spike
}

// ── 3. Greedy VRP — assign shipments to trucks ───────────────
const trucks = fleet.map(f => ({ ...f, assigned: [], load: 0 }));

for (const ship of sorted) {
  // Find truck with most remaining capacity that can fit this shipment
  const candidates = trucks
    .filter(t => t.load + ship.weight_kg <= t.capacity_kg)
    .sort((a,b) => (b.capacity_kg - b.load) - (a.capacity_kg - a.load));

  if (candidates.length === 0) {
    // Overflow — add to truck with most capacity anyway
    trucks.sort((a,b) => b.capacity_kg - a.capacity_kg)[0].assigned.push(ship);
    trucks[0].load += ship.weight_kg;
  } else {
    candidates[0].assigned.push(ship);
    candidates[0].load += ship.weight_kg;
  }
}

// ── 4. Build optimized routes ────────────────────────────────
const routes = [];
let totalCost = 0;
let allFactors = [];
let spikesCount = 0;

for (const truck of trucks) {
  if (truck.assigned.length === 0) continue;

  const factors = truck.assigned.map(s => getFactor(s.dest));
  const avgFactor = factors.reduce((a,b) => a+b, 0) / factors.length;
  const hasSpike = factors.some(f => f > 1.15);
  if (hasSpike) spikesCount++;

  // ETA — start 09:00, +35min * factor per stop
  let etaMin = 9 * 60;
  const etaList = truck.assigned.map((s, i) => {
    etaMin += Math.round(35 * factors[i]);
    const h = Math.floor(etaMin / 60);
    const m = etaMin % 60;
    return `${s.id}@${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}`;
  });

  // Total travel time
  const travelMin = truck.assigned.reduce((sum, s, i) => sum + Math.round(35 * factors[i]), 0);
  const travelH = Math.floor(travelMin / 60);
  const travelM = travelMin % 60;
  const travelStr = hasSpike
    ? `${travelH}h ${travelM}m (rerouted +5%)`
    : `${travelH}h ${travelM}m`;

  // Cost = load * 0.12 + stops * 24
  const cost = parseFloat((truck.load * 0.12 + truck.assigned.length * 24).toFixed(2));
  totalCost += cost;

  // Fuel efficiency
  const fuelScore = Math.max(0, Math.round(100 - (avgFactor - 1.0) * 200));
  allFactors.push(avgFactor);

  // Destination cities
  const cities = [...new Set(truck.assigned.map(s => s.dest))].join(' → ');

  // Stop sequence
  const stopSeq = truck.assigned.map((s,i) => `${i+1}.${s.id}`).join(', ');

  routes.push({
    Route_ID: `${truck.id}-${run_id.slice(-6)}`,
    truck_id: truck.id,
    driver: truck.driver,
    Destination_City: cities,
    Stop_Sequence: stopSeq,
    Estimated_Travel_Time: travelStr,
    Fuel_Efficiency_Score: fuelScore,
    Optimized_Path_Notes: `${truck.id} | ${etaList.join(', ')}${hasSpike ? ' | Rerouted +5%' : ''}`,
    load_kg: truck.load,
    cost_usd: cost,
    rerouted: hasSpike
  });
}

const avgFuelScore = routes.length
  ? Math.round(routes.reduce((s,r) => s + r.Fuel_Efficiency_Score, 0) / routes.length)
  : 0;

// ── 5. HOS compliance check ──────────────────────────────────
let violatedTrucks = 0, warningTrucks = 0, compliantTrucks = 0;
const hosStatus = fleet.map(f => {
  const driveHours = f.assigned?.length ? f.assigned.length * 0.6 : 0;
  const totalHours = f.hours_used + (trucks.find(t=>t.id===f.id)?.assigned.length || 0) * 0.6;
  const violation = totalHours >= hos_limit;
  const warning   = !violation && totalHours >= 9;
  if (violation) violatedTrucks++;
  else if (warning) warningTrucks++;
  else compliantTrucks++;
  return {
    truck_id: f.id,
    driver: f.driver,
    hours_used: parseFloat(totalHours.toFixed(1)),
    hours_remaining: parseFloat((hos_limit - totalHours).toFixed(1)),
    compliant: !violation,
    warning
  };
});

// ── 6. Risk score ─────────────────────────────────────────────
const totalCapacity = fleet.reduce((s,f) => s + f.capacity_kg, 0);
const totalLoad     = routes.reduce((s,r) => s + r.load_kg, 0);
const utilPct       = parseFloat((totalLoad / totalCapacity * 100).toFixed(1));

const riskScore = Math.min(100,
  violatedTrucks * 40 +
  warningTrucks  * 15 +
  spikesCount    * 10 +
  (utilPct > 85  ? 20 : 0)
);

const riskLevel = riskScore >= 60 ? 'CRITICAL'
                : riskScore >= 30 ? 'HIGH'
                : riskScore >= 10 ? 'MEDIUM'
                : 'LOW';

const riskFlags = [];
if (violatedTrucks > 0) riskFlags.push(`HOS VIOLATION: ${violatedTrucks} truck(s)`);
if (warningTrucks  > 0) riskFlags.push(`HOS WARNING: ${warningTrucks} truck(s)`);
if (spikesCount    > 0) riskFlags.push(`TRAFFIC SPIKE: ${spikesCount} route(s)`);
if (utilPct > 85)        riskFlags.push(`HIGH UTILIZATION: ${utilPct}%`);

// ── 7. Decision ───────────────────────────────────────────────
const canDispatch = violatedTrucks === 0 && riskLevel !== 'CRITICAL';
let decision, confidence;
if (!canDispatch || riskLevel === 'CRITICAL') {
  decision = 'halt';   confidence = 0.99;
} else if (riskLevel === 'HIGH' || riskScore >= 30) {
  decision = 'review'; confidence = parseFloat((0.70 + (60-riskScore)/200).toFixed(2));
} else {
  decision = 'approve';
  confidence = parseFloat(Math.min(0.99, 0.85 + (100-riskScore)/1000).toFixed(2));
}

// ── 8. Reward signal ──────────────────────────────────────────
const dataQuality = shipments.length > 0 ? 1.0 : 0;
const routeScore  = avgFuelScore / 100;
const riskVal     = riskLevel==='LOW'?1.0:riskLevel==='MEDIUM'?0.8:riskLevel==='HIGH'?0.6:0.3;
const decScore    = decision==='approve'?1.0:decision==='review'?0.7:0.3;
const base        = shipments.length / Math.max(totalCost / 100, 1);
const rewardSignal= parseFloat((base * dataQuality * routeScore * riskVal * decScore).toFixed(3));

// ── 9. Priority breakdown ─────────────────────────────────────
const byPriority = shipments.reduce((acc, s) => {
  const k = (s.priority || 'Medium').toLowerCase();
  acc[k] = (acc[k] || 0) + 1;
  return acc;
}, {});

const manifest_id = 'AMAN-' + Date.now();
console.log(`[Compute] ${manifest_id} | ${decision} | $${totalCost.toFixed(2)} | risk=${riskScore}/${riskLevel} | routes=${routes.length}`);

return [{ json: {
  // Pass through
  run_id,
  timestamp: d.timestamp,
  manifest_id,
  total_shipments: shipments.length,
  shipments,
  fleet,
  trafficFactors,
  hos_limit,

  // Computed results
  data_result: {
    total_valid: shipments.length,
    total_invalid: 0,
    total_weight_kg: totalLoad,
    by_priority: byPriority,
    data_quality_score: dataQuality
  },

  route_result: {
    optimized_routes: routes,
    total_cost_usd: parseFloat(totalCost.toFixed(2)),
    avg_fuel_score: avgFuelScore,
    trucks_used: routes.length,
    has_reroute: routes.some(r => r.rerouted)
  },

  risk_result: {
    risk_score: riskScore,
    risk_level: riskLevel,
    risk_flags: riskFlags,
    can_dispatch: canDispatch,
    compliant_trucks: compliantTrucks,
    warning_trucks: warningTrucks,
    violated_trucks: violatedTrucks,
    spikes_count: spikesCount,
    has_spike: spikesCount > 0,
    capacity_utilization: utilPct,
    hos_status: hosStatus
  },

  decision,
  confidence,
  reward_signal: rewardSignal,
  total_cost_usd: parseFloat(totalCost.toFixed(2)),
  avg_fuel_score: avgFuelScore
}}];

// ── STEP 4: ASSEMBLE FINAL OUTPUT ───────────────────────────
// Merge computed data + AI summary into the final response object

const d = $input.first().json;

// Extract summary text from Groq agent output
function extractText(obj) { return obj.summary || ''; }

const summary = extractText(d);
console.log('[Assemble] summary:', summary.slice(0,100));

// Build priority action list from real flags
const priority_actions = [];
if (d.risk_result.violated_trucks > 0) priority_actions.push('Address HOS violations before dispatch');
if (d.risk_result.has_spike)           priority_actions.push('Monitor rerouted routes for delays');
if (d.decision === 'approve')          priority_actions.push(`Depart at 09:00 — ${d.route_result.trucks_used} trucks dispatched`);
if (d.decision === 'review')           priority_actions.push('Manual review required before dispatch');
if (d.decision === 'halt')             priority_actions.push('Do NOT dispatch — critical risk detected');

return [{ json: {
  // Identity
  manifest_id:      d.manifest_id,
  run_id:           d.run_id,
  agentic_workflow: true,
  source:           'google_sheets',
  assembled_at:     new Date().toISOString(),

  // Top-level metrics (for dashboard)
  total_shipments:  d.total_shipments,
  total_cost_usd:   d.total_cost_usd,
  avg_fuel_score:   d.avg_fuel_score,

  // Decision block
  ai: {
    decision:              d.decision,
    confidence:            d.confidence,
    summary,
    priority_actions,
    risk_flags:            d.risk_result.risk_flags,
    estimated_savings_pct: d.decision === 'approve' ? Math.round((1 - d.avg_fuel_score/100) * 100 * 0.18) : 0,
    recommended_departure: d.decision === 'approve' ? '09:00' : 'HOLD',
    agent_notes: `Computed from ${d.total_shipments} real shipments. Risk ${d.risk_result.risk_score}/100 (${d.risk_result.risk_level}). Decision: ${d.decision.toUpperCase()} at ${(d.confidence*100).toFixed(0)}% confidence.`
  },

  // Agentic loop summary
  agentic_summary: {
    total_iterations: 1,
    quality_score:    Math.max(0, Math.round(100 - d.risk_result.risk_score * 0.3)),
    hitl_triggered:   d.decision === 'halt' || d.risk_result.risk_score >= 80,
    reward_signal:    d.reward_signal,
    planning_notes:   [`${d.total_shipments} shipments loaded`, `${d.route_result.trucks_used} routes computed`, `Risk ${d.risk_result.risk_level}`]
  },

  // Routes for display
  dispatched: d.route_result.optimized_routes,

  // HOS
  has_spike:      d.risk_result.has_spike,
  hos_violations: d.risk_result.hos_status.filter(h=>!h.compliant).map(h=>h.driver),
  hos_status:     d.risk_result.hos_status,

  // Risk
  risk_summary: {
    risk_level:   d.risk_result.risk_level,
    risk_score:   d.risk_result.risk_score,
    can_dispatch: d.risk_result.can_dispatch
  },

  // Data quality
  data_summary: {
    total_valid:        d.data_result.total_valid,
    data_quality_score: d.data_result.data_quality_score
  },

  // Full results for email / write
  route_result: d.route_result,
  risk_result:  d.risk_result,
  data_result:  d.data_result
}}];

// Generate summary from computed data — no LLM needed
const d = $input.first().json;
const ai_dec = d.decision || 'unknown';
const risk   = d.risk_result || {};
const routes = d.route_result || {};
const ships  = d.total_shipments || 0;
const cost   = d.total_cost_usd || 0;

// Build plain-English summary from real computed values
const parts = [
  `${ships} shipment${ships!==1?'s':''} processed across ${routes.trucks_used||0} truck${(routes.trucks_used||0)!==1?'s':''}.`,
  `Decision: ${ai_dec.toUpperCase()} at ${((d.confidence||0)*100).toFixed(0)}% confidence.`,
  `Total cost: $${cost}. Risk: ${risk.risk_level||'UNKNOWN'} (${risk.risk_score||0}/100).`,
];
if (risk.has_spike)          parts.push(`Traffic spike detected — reroute buffer applied.`);
if (risk.violated_trucks>0)  parts.push(`Warning: ${risk.violated_trucks} HOS violation(s) detected.`);
if (risk.warning_trucks>0)   parts.push(`${risk.warning_trucks} driver(s) approaching HOS limit.`);
if (ai_dec==='approve')      parts.push(`Dispatch cleared. Recommended departure: 09:00.`);
if (ai_dec==='review')       parts.push(`Manual review required before dispatch.`);
if (ai_dec==='halt')         parts.push(`Dispatch halted — do not proceed without resolution.`);

const summary = parts.join(' ');
console.log('[Summary]', summary);

// Pass everything through with summary added
return [{ json: { ...d, summary } }];
